import{_ as o,o as r,c as s,a2 as e}from"./chunks/framework.DvFsUg-r.js";const d=JSON.parse('{"title":"메인 최근 글 전용 + 시간 정밀 정렬 + 이미지 오표시 수정","description":"","frontmatter":{"title":"메인 최근 글 전용 + 시간 정밀 정렬 + 이미지 오표시 수정","feature_id":"011","status":"done","created":"2026-06-03 09:03 (KST)","date":"2026-06-03T00:00:00.000Z","tags":["vitepress","home","content-loader","bugfix","ux"]},"headers":[],"relativePath":"specs/011-home-recent-only/spec.md","filePath":"specs/011-home-recent-only/spec.md","lastUpdated":null}'),a={name:"specs/011-home-recent-only/spec.md"};function n(i,t,l,g,h,c){return r(),s("div",null,[...t[0]||(t[0]=[e('<h1 id="spec-메인-최근-글-전용-시간-정밀-정렬-이미지-오표시-수정" tabindex="-1">Spec: 메인 최근 글 전용 + 시간 정밀 정렬 + 이미지 오표시 수정 <a class="header-anchor" href="#spec-메인-최근-글-전용-시간-정밀-정렬-이미지-오표시-수정" aria-label="Permalink to &quot;Spec: 메인 최근 글 전용 + 시간 정밀 정렬 + 이미지 오표시 수정&quot;">​</a></h1><h2 id="why-문제-목적" tabindex="-1">Why (문제 / 목적) <a class="header-anchor" href="#why-문제-목적" aria-label="Permalink to &quot;Why (문제 / 목적)&quot;">​</a></h2><p>기능 010 으로 메인 화면에 hero + 기존 6개 기능 카드 + 최근 글 목록이 함께 놓였다. 운영 결과 세 가지를 개선하려 한다.</p><ol><li><strong>메인을 최근 글 중심으로</strong> — 기능 카드보다 &quot;방금 무엇이 올라왔는가&quot;가 더 중요하다. 메인 콘텐츠를 <strong>최근 글만</strong> 보여주도록 단순화한다.</li><li><strong>시간 정밀도 부족</strong> — 현재 정렬·표기가 <strong>날짜(일) 단위</strong>라, 같은 날 올린 글의 선후가 흔들리고 &quot;방금 등록한 글&quot;이 맨 위로 확실히 오지 않는다. <strong>시·분·초까지</strong> 반영해 가장 최근 등록 글이 정확히 먼저 오게 한다.</li><li><strong>이미지 오표시 버그</strong> — 이미지가 없는 글인데 목록에 (깨진) 이미지가 표시된다. 원인은 글 본문의 <strong>코드블록/예시 안의 이미지 표기</strong>(설명용 <code>![](경로)</code> 같은 예시)를 실제 대표 이미지로 잘못 인식하는 것이다. 실제 이미지가 있는 글만 이미지를 보여주도록 고친다.</li></ol><h2 id="clarifications" tabindex="-1">Clarifications <a class="header-anchor" href="#clarifications" aria-label="Permalink to &quot;Clarifications&quot;">​</a></h2><h3 id="session-2026-06-03" tabindex="-1">Session 2026-06-03 <a class="header-anchor" href="#session-2026-06-03" aria-label="Permalink to &quot;Session 2026-06-03&quot;">​</a></h3><ul><li>Q: &quot;최근글만&quot; 메인에서 hero 섹션은? → A: <strong>hero 유지 + 6개 기능 카드만 제거</strong>(브랜드 hero 는 남긴다).</li><li>Q: 최근 글 목록 노출 개수는? → A: <strong>상위 20개</strong> + 전체 보기 링크.</li><li>Q: 등록 시각 정보가 없는 글(날짜만)의 표기는? → A: <strong>날짜만 표기</strong>(시:분:초 생략). 시각이 있는 글만 <code>HH:MM:SS</code> 표기.</li></ul><h2 id="what-범위" tabindex="-1">What (범위) <a class="header-anchor" href="#what-범위" aria-label="Permalink to &quot;What (범위)&quot;">​</a></h2><h3 id="포함" tabindex="-1">포함 <a class="header-anchor" href="#포함" aria-label="Permalink to &quot;포함&quot;">​</a></h3><ul><li>메인 화면 콘텐츠를 <strong>최근 글 목록만</strong> 노출(기존 6개 기능 카드 제거).</li><li>최근 글 <strong>정렬을 시·분·초까지</strong> 정밀화 — 가장 최근 등록 글이 맨 위.</li><li>최근 글 <strong>표기에 시각(시·분·초)</strong> 포함.</li><li><strong>이미지 오표시 버그 수정</strong> — 본문 코드블록/예시 등 비실제 이미지 표기를 대표 이미지로 쓰지 않는다. 진짜 이미지가 없으면 이미지를 표시하지 않는다.</li></ul><h3 id="제외-non-goals" tabindex="-1">제외 (Non-goals) <a class="header-anchor" href="#제외-non-goals" aria-label="Permalink to &quot;제외 (Non-goals)&quot;">​</a></h3><ul><li>글 본문 작성·수정.</li><li>상단 메뉴/사이드바 구조 변경(009), 블로그 제목(010 에서 완료).</li><li>페이지네이션·무한 스크롤, 카테고리/태그 페이지.</li><li>날짜 없는 섹션(Cowork·Hermes·스킬 강연)의 피드 편입(별도 과제).</li></ul><h2 id="user-scenarios" tabindex="-1">User Scenarios <a class="header-anchor" href="#user-scenarios" aria-label="Permalink to &quot;User Scenarios&quot;">​</a></h2><ol><li><strong>첫 방문자</strong>: 메인에 들어오면 군더더기 없이 <strong>최근 글 목록</strong>이 바로 보인다(기능 카드 없음).</li><li><strong>방금 글을 올린 운영자</strong>: 같은 날 여러 글을 올려도, <strong>초 단위</strong>까지 반영돼 방금 등록한 글이 <strong>확실히 맨 위</strong>에 온다. 목록에서 등록 시각(시·분·초)을 본다.</li><li><strong>이미지 없는 글</strong>: 대표 이미지가 없는 글은 목록에서 <strong>이미지 없이</strong> 깔끔히 표시된다(깨진 이미지·엉뚱한 이미지 없음).</li><li><strong>이미지 있는 글</strong>: 진짜 대표 이미지가 있는 글만 썸네일이 보인다.</li></ol><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="메인-콘텐츠-최근-글-전용" tabindex="-1">메인 콘텐츠 (최근 글 전용) <a class="header-anchor" href="#메인-콘텐츠-최근-글-전용" aria-label="Permalink to &quot;메인 콘텐츠 (최근 글 전용)&quot;">​</a></h3><ul><li><strong>FR-1</strong>: 메인 화면 콘텐츠는 <strong>최근 글 목록만</strong> 표시한다. 기존 6개 기능 카드는 제거한다. <strong>브랜드 hero 섹션(제목·태그라인·버튼)은 유지</strong>한다.</li><li><strong>FR-2</strong>: 최근 글 목록은 최신순으로 상위 <strong>20개</strong>를 노출하고, 전체 목록 진입(더 보기) 링크를 유지한다.</li></ul><h3 id="시간-정밀-정렬·표기" tabindex="-1">시간 정밀 정렬·표기 <a class="header-anchor" href="#시간-정밀-정렬·표기" aria-label="Permalink to &quot;시간 정밀 정렬·표기&quot;">​</a></h3><ul><li><strong>FR-3</strong>: 최근 글 정렬 키는 <strong>시·분·초까지</strong> 포함한 등록 시각을 사용한다. 같은 날짜의 글도 시각으로 선후가 결정되어, 가장 최근 등록 글이 맨 위에 온다.</li><li><strong>FR-4</strong>: 각 항목의 날짜 표기에 <strong>시각(시·분·초)</strong> 을 포함한다(예: <code>YYYY-MM-DD HH:MM:SS</code>). 시각 정보가 없는 글은 가능한 범위(날짜)만 표기한다.</li><li><strong>FR-5</strong>: 시각 메타데이터가 글마다 다른 필드에 있을 수 있으므로, 가장 정밀한 값을 우선 사용한다(시각 포함 값 &gt; 날짜만 있는 값).</li></ul><h3 id="이미지-오표시-수정-버그" tabindex="-1">이미지 오표시 수정 (버그) <a class="header-anchor" href="#이미지-오표시-수정-버그" aria-label="Permalink to &quot;이미지 오표시 수정 (버그)&quot;">​</a></h3><ul><li><strong>FR-6</strong>: 대표 이미지 추출 시 <strong>본문 코드블록/인라인 코드 안의 이미지 표기와 설명용 예시</strong>는 제외한다. 실제 콘텐츠 이미지가 아닌 표기를 대표 이미지로 쓰지 않는다.</li><li><strong>FR-7</strong>: 유효한 대표 이미지가 없으면 <strong>이미지를 표시하지 않는다</strong>(깨진 이미지·자리표시·엉뚱한 경로 노출 금지).</li><li><strong>FR-8</strong>: 추출된 이미지 경로가 유효하지 않거나 로드에 실패해도 목록 렌더링이 깨지지 않는다.</li></ul><h3 id="품질-·-보존" tabindex="-1">품질 · 보존 <a class="header-anchor" href="#품질-·-보존" aria-label="Permalink to &quot;품질 · 보존&quot;">​</a></h3><ul><li><strong>FR-9</strong>: 변경은 <strong>빌드(strict)</strong> 를 통과한다(깨진 내부 링크 0).</li><li><strong>FR-10</strong>: 기존 글 URL·콘텐츠 경로는 변경하지 않는다.</li></ul><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li><strong>SC-1</strong>: 메인 화면에 기능 카드가 더 이상 보이지 않고, <strong>최근 글 목록만</strong> 노출된다.</li><li><strong>SC-2</strong>: 같은 날짜에 등록된 두 글의 순서가 <strong>등록 시각(초 단위)</strong> 으로 정확히 결정되어, 가장 최근 글이 맨 위에 온다.</li><li><strong>SC-3</strong>: 각 글 항목에 <strong>시·분·초</strong> 가 표기된다(시각 정보가 있는 글의 경우).</li><li><strong>SC-4</strong>: 대표 이미지가 없는 글에는 <strong>이미지가 전혀 표시되지 않는다</strong>(오표시 0건). 실제 이미지가 있는 글만 썸네일이 보인다.</li><li><strong>SC-5</strong>: 변경 후 빌드(strict) 통과, 기존 URL 회귀 0.</li></ul><h2 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h2><ul><li><strong>글(Post)</strong>: 제목, <strong>등록 시각(시·분·초 포함)</strong>, 요약, 대표 이미지(실제 이미지에 한함), 링크.</li><li><strong>메인 글 목록(Home Feed)</strong>: 글의 시각 기준 최신순 컬렉션(상위 N).</li></ul><h2 id="assumptions" tabindex="-1">Assumptions <a class="header-anchor" href="#assumptions" aria-label="Permalink to &quot;Assumptions&quot;">​</a></h2><ul><li><strong>hero 섹션은 유지</strong>한다(&quot;최근 글만&quot;은 기능 카드 제거를 의미하며, 브랜드 hero 는 남긴다) — Clarifications 2026-06-03 확정.</li><li>노출 개수는 <strong>상위 20개</strong>(010 의 8개 → 20개) — Clarifications 확정.</li><li>등록 시각은 frontmatter 의 시각 포함 값(예: <code>date</code>/<code>created</code> 의 시간 부분, ISO 타임스탬프)을 우선 사용한다. 시각이 없으면 날짜만 표기·정렬한다.</li><li>표기 형식은 <code>YYYY-MM-DD HH:MM:SS</code> (사이트 기준 시간대, KST).</li><li>대표 이미지는 frontmatter 이미지 필드 또는 <strong>본문(코드블록 제외)의 실제 이미지</strong>만 인정한다.</li><li>콘텐츠 파일 경로·URL 은 변경하지 않는다.</li></ul><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><ul><li>초기 Open Questions(hero 유지 여부·노출 개수·시각 없는 글 표기)는 <strong>2026-06-03 Clarifications 에서 모두 해소</strong>되었다. 현재 미해결 결정 없음.</li></ul>',31)])])}const q=o(a,[["render",n]]);export{d as __pageData,q as default};
